class ExamRoom {

    private int n;
    private List<Integer> seats;

    public ExamRoom(int n) {
        this.n = n;
        this.seats = new ArrayList<>();
    }

    public int seat() {
        if (seats.isEmpty()) {
            seats.add(0);
            return 0;
        }
        int maxDistance = -1;
        int seat = -1;
        if (seats.get(0) != 0) {
            int distance = seats.get(0);
            if (distance > maxDistance) {
                maxDistance = distance;
                seat = 0;
            }
        }
        for (int i = 0; i < seats.size() - 1; i++) {
            int distance = (seats.get(i + 1) - seats.get(i)) / 2;
            if (distance > maxDistance) {
                maxDistance = distance;
                seat = seats.get(i) + distance;
            }
        }
        if (seats.get(seats.size() - 1) != n - 1) {
            int distance = n - 1 - seats.get(seats.size() - 1);
            if (distance > maxDistance) {
                maxDistance = distance;
                seat = n - 1;
            }
        }
        seats.add(seat);
        Collections.sort(seats);
        return seat;
    }

    public void leave(int p) {
        seats.remove(Integer.valueOf(p));
    }
}
